/**
 * API Tests: Authentication Endpoints
 * Epic 1: User Authentication and Management
 *
 * P0-API-001 to P0-API-004
 *
 * Tests cover:
 * - POST /api/auth/login (P0)
 * - POST /api/auth/logout (P0)
 * - POST /api/auth/register (P1)
 * - POST /api/auth/reset-password (P0)
 *
 * Testing Approach:
 * - Uses Playwright's APIRequestContext for direct API calls
 * - Tests authentication flow and session management
 * - Validates error handling and edge cases
 * - Includes contract tests for request/response schemas
 *
 * Contract Testing:
 * - Uses Pact.js patterns for provider state verification
 * - Validates response schemas match consumer expectations
 * - Tests authentication headers and token formats
 */

import { test, expect } from '@playwright/test';
import { faker } from '@faker-js/faker/locale/es';

/**
 * Auth API Tests
 *
 * Note: These tests use NextAuth.js which handles authentication via
 * the /api/auth/[...nextauth] route. Tests verify the authentication
 * flow through NextAuth's credentials provider.
 */

test.describe('Auth API Endpoints', () => {
  let baseURL: string;

  test.beforeAll(async () => {
    baseURL = process.env.BASE_URL || 'http://localhost:3000';
  });

  test.describe('POST /api/auth/signin (Login)', () => {
    /**
     * P0-API-001: Successful login with valid credentials
     *
     * AC1: Given usuario con credenciales válidas
     *       When inicia sesión
     *       Then recibe respuesta 200 OK
     *       And session cookie es establecida
     *       And response contiene user data con capabilities
     *
     * Contract Test:
     * - Response status: 200
     * - Response body: { user: { id, email, name, capabilities[] } }
     * - Set-Cookie header presente con session token
     */
    test('[P0-API-001] should login successfully with valid credentials', async ({ request }) => {
      const loginData = {
        email: 'admin@hiansa.com',
        password: 'admin123',
      };

      const response = await request.post(`${baseURL}/api/auth/callback/credentials`, {
        data: loginData,
        headers: {
          'Content-Type': 'application/json',
        },
      });

      // NextAuth redirects on success, so we expect a 302 or 200
      expect([200, 302, 303]).toContain(response.status());

      if (response.status() === 200) {
        const body = await response.json();
        expect(body).toHaveProperty('user');
        expect(body.user).toHaveProperty('id');
        expect(body.user).toHaveProperty('email', loginData.email);
        expect(body.user).toHaveProperty('capabilities');
        expect(Array.isArray(body.user.capabilities)).toBeTruthy();
      }

      // Verify session cookie is set
      const cookies = response.headers()['set-cookie'];
      expect(cookies).toBeDefined();
      expect(cookies).toContain('next-auth.session-token');
    });

    /**
     * P0-API-002: Login fails with invalid credentials
     *
     * AC2: Given usuario con credenciales inválidas
     *       When intenta iniciar sesión
     *       Then recibe respuesta 401 Unauthorized
     *       And response contiene error message
     *
     * Contract Test:
     * - Response status: 401
     * - Response body: { error: string }
     * - No session cookie establecida
     */
    test('[P0-API-002] should fail login with invalid credentials', async ({ request }) => {
      const loginData = {
        email: 'admin@hiansa.com',
        password: 'wrongpassword',
      };

      const response = await request.post(`${baseURL}/api/auth/callback/credentials`, {
        data: loginData,
        headers: {
          'Content-Type': 'application/json',
        },
      });

      // NextAuth returns error with 401 or redirect to error page
      expect([401, 302]).toContain(response.status());

      const cookies = response.headers()['set-cookie'];
      if (response.status() === 401) {
        const body = await response.json();
        expect(body).toHaveProperty('error');
        expect(cookies).toBeUndefined();
      }
    });

    /**
     * P0-API-003: Login fails with missing credentials
     *
     * AC3: Given usuario sin email o password
     *       When intenta iniciar sesión
     *       Then recibe respuesta 400 Bad Request
     *       And response contiene validation error
     *
     * Contract Test:
     * - Response status: 400
     * - Response body: { error: string }
     */
    test('[P0-API-003] should fail login with missing credentials', async ({ request }) => {
      const loginData = {
        email: '',
        password: '',
      };

      const response = await request.post(`${baseURL}/api/auth/callback/credentials`, {
        data: loginData,
        headers: {
          'Content-Type': 'application/json',
        },
      });

      expect([400, 401]).toContain(response.status());
    });

    /**
     * P0-API-004: Login fails for deleted user
     *
     * AC4: Given usuario marcado como deleted
     *       When intenta iniciar sesión
     *       Then recibe respuesta 401 Unauthorized
     *       And response contiene mensaje específico
     *
     * Contract Test:
     * - Response status: 401
     * - Response body: { error: "Este usuario ha sido eliminado..." }
     */
    test('[P0-API-004] should fail login for deleted user', async ({ request }) => {
      const loginData = {
        email: 'deleted@hiansa.com', // Assuming this user exists and is deleted
        password: 'password123',
      };

      const response = await request.post(`${baseURL}/api/auth/callback/credentials`, {
        data: loginData,
        headers: {
          'Content-Type': 'application/json',
        },
      });

      // Should fail with 401
      expect([401, 302]).toContain(response.status());
    });

    /**
     * P0-API-005: Rate limiting on login attempts
     *
     * AC5: Given múltiples intentos de login fallidos
     *       When excede el límite de rate limit
     *       Then recibe respuesta 429 Too Many Requests
     *       And response contiene mensaje de retry
     *
     * Contract Test:
     * - Response status: 429
     * - Response body: { error: "Demasiados intentos..." }
     * - Retry-After header presente
     */
    test('[P0-API-005] should enforce rate limiting on login', async ({ request }) => {
      const loginData = {
        email: 'admin@hiansa.com',
        password: 'wrongpassword',
      };

      // Make multiple failed login attempts
      const attempts = [];
      for (let i = 0; i < 6; i++) {
        attempts.push(
          request.post(`${baseURL}/api/auth/callback/credentials`, {
            data: loginData,
            headers: {
              'Content-Type': 'application/json',
            },
          })
        );
      }

      const responses = await Promise.all(attempts);
      const lastResponse = responses[responses.length - 1];

      // Should be rate limited after 5 attempts
      expect([401, 429]).toContain(lastResponse.status());

      if (lastResponse.status() === 429) {
        const body = await lastResponse.json();
        expect(body.error).toContain('Demasiados intentos');
      }
    });
  });

  test.describe('POST /api/auth/signout (Logout)', () => {
    /**
     * P0-API-006: Successful logout
     *
     * AC1: Given usuario autenticado
     *       When cierra sesión
     *       Then recibe respuesta 200 OK
     *       And session cookie es eliminada
     *
     * Contract Test:
     * - Response status: 200
     * - Set-Cookie header con expired session token
     */
    test('[P0-API-006] should logout successfully', async ({ request }) => {
      const response = await request.post(`${baseURL}/api/auth/signout`, {
        headers: {
          'Content-Type': 'application/json',
        },
      });

      expect([200, 302]).toContain(response.status());

      const cookies = response.headers()['set-cookie'];
      if (cookies) {
        expect(cookies).toContain('next-auth.session-token=');
        expect(cookies).toContain('Expires=');
      }
    });
  });

  test.describe('POST /api/auth/register (User Registration)', () => {
    /**
     * P1-API-001: Create new user via registration
     *
     * AC1: Given admin autenticado
     *       When registra nuevo usuario
     *       Then recibe respuesta 201 Created
     *       And response contiene user data
     *       And usuario tiene can_create_failure_report por defecto
     *
     * Contract Test:
     * - Response status: 201
     * - Response body: { user: { id, email, name, capabilities[] } }
     * - capabilities contiene ["can_create_failure_report"]
     */
    test('[P1-API-001] should create new user with default capability', async ({ request }) => {
      // First login as admin to get session
      const loginResponse = await request.post(`${baseURL}/api/auth/callback/credentials`, {
        data: {
          email: 'admin@hiansa.com',
          password: 'admin123',
        },
      });

      const cookies = loginResponse.headers()['set-cookie'];
      const cookieHeader = cookies?.split(';')[0] || '';

      const userData = {
        email: `test-${faker.string.uuid()}@example.com`,
        name: faker.person.fullName(),
        password: 'TempPassword123!',
        phone: `+34${faker.string.numeric(9)}`,
      };

      const response = await request.post(`${baseURL}/api/v1/users`, {
        data: userData,
        headers: {
          'Content-Type': 'application/json',
          'Cookie': cookieHeader,
        },
      });

      expect(response.status()).toBe(201);
      const body = await response.json();
      expect(body).toHaveProperty('user');
      expect(body.user).toHaveProperty('id');
      expect(body.user).toHaveProperty('email', userData.email);
      expect(body.user).toHaveProperty('capabilities');
      expect(body.user.capabilities).toContain('can_create_failure_report');
    });

    /**
     * P1-API-002: Registration fails with duplicate email
     *
     * AC2: Given email ya registrado
     *       When intenta registrar usuario con mismo email
     *       Then recibe respuesta 409 Conflict
     *       And response contiene error message
     *
     * Contract Test:
     * - Response status: 409
     * - Response body: { error: string }
     */
    test('[P1-API-002] should fail registration with duplicate email', async ({ request }) => {
      const loginResponse = await request.post(`${baseURL}/api/auth/callback/credentials`, {
        data: {
          email: 'admin@hiansa.com',
          password: 'admin123',
        },
      });

      const cookies = loginResponse.headers()['set-cookie'];
      const cookieHeader = cookies?.split(';')[0] || '';

      const userData = {
        email: 'admin@hiansa.com', // Already exists
        name: faker.person.fullName(),
        password: 'TempPassword123!',
      };

      const response = await request.post(`${baseURL}/api/v1/users`, {
        data: userData,
        headers: {
          'Content-Type': 'application/json',
          'Cookie': cookieHeader,
        },
      });

      expect(response.status()).toBe(409);
      const body = await response.json();
      expect(body).toHaveProperty('error');
    });

    /**
     * P1-API-003: Registration fails with invalid data
     *
     * AC3: Given datos inválidos (email mal formado, password muy corto)
     *       When intenta registrar usuario
     *       Then recibe respuesta 400 Bad Request
     *       And response contiene validation errors
     *
     * Contract Test:
     * - Response status: 400
     * - Response body: { error: string, details?: object }
     */
    test('[P1-API-003] should fail registration with invalid data', async ({ request }) => {
      const loginResponse = await request.post(`${baseURL}/api/auth/callback/credentials`, {
        data: {
          email: 'admin@hiansa.com',
          password: 'admin123',
        },
      });

      const cookies = loginResponse.headers()['set-cookie'];
      const cookieHeader = cookies?.split(';')[0] || '';

      const userData = {
        email: 'invalid-email',
        name: faker.person.fullName(),
        password: '123', // Too short
      };

      const response = await request.post(`${baseURL}/api/v1/users`, {
        data: userData,
        headers: {
          'Content-Type': 'application/json',
          'Cookie': cookieHeader,
        },
      });

      expect(response.status()).toBe(400);
      const body = await response.json();
      expect(body).toHaveProperty('error');
    });
  });

  test.describe('POST /api/auth/reset-password (Password Reset)', () => {
    /**
     * P0-API-007: Request password reset
     *
     * AC1: Given usuario olvida su password
     *       When solicita reset de password
     *       Then recibe respuesta 200 OK
     *       And sistema envía email con token de reset
     *
     * Contract Test:
     * - Response status: 200
     * - Response body: { message: string }
     */
    test('[P0-API-007] should request password reset', async ({ request }) => {
      const resetData = {
        email: 'admin@hiansa.com',
      };

      const response = await request.post(`${baseURL}/api/v1/users/request-password-reset`, {
        data: resetData,
        headers: {
          'Content-Type': 'application/json',
        },
      });

      // This endpoint may not be implemented yet
      // If it exists, expect 200; if not, expect 404
      expect([200, 404, 501]).toContain(response.status());

      if (response.status() === 200) {
        const body = await response.json();
        expect(body).toHaveProperty('message');
      }
    });

    /**
     * P0-API-008: Reset password with valid token
     *
     * AC2: Given token de reset válido
     *       When envía nueva password
     *       Then recibe respuesta 200 OK
     *       And password es actualizada
     *
     * Contract Test:
     * - Response status: 200
     * - Response body: { message: string }
     */
    test('[P0-API-008] should reset password with valid token', async ({ request }) => {
      const resetData = {
        token: 'valid-reset-token',
        newPassword: 'NewPassword123!',
      };

      const response = await request.post(`${baseURL}/api/v1/users/reset-password`, {
        data: resetData,
        headers: {
          'Content-Type': 'application/json',
        },
      });

      // This endpoint may not be implemented yet
      expect([200, 400, 401, 404, 501]).toContain(response.status());

      if (response.status() === 200) {
        const body = await response.json();
        expect(body).toHaveProperty('message');
      }
    });

    /**
     * P0-API-009: Reset password fails with invalid token
     *
     * AC3: Given token de reset inválido o expirado
     *       When intenta resetear password
     *       Then recibe respuesta 400 Bad Request
     *       And response contiene error message
     *
     * Contract Test:
     * - Response status: 400
     * - Response body: { error: string }
     */
    test('[P0-API-009] should fail password reset with invalid token', async ({ request }) => {
      const resetData = {
        token: 'invalid-token',
        newPassword: 'NewPassword123!',
      };

      const response = await request.post(`${baseURL}/api/v1/users/reset-password`, {
        data: resetData,
        headers: {
          'Content-Type': 'application/json',
        },
      });

      // This endpoint may not be implemented yet
      expect([400, 401, 404, 501]).toContain(response.status());

      if ([400, 401].includes(response.status())) {
        const body = await response.json();
        expect(body).toHaveProperty('error');
      }
    });
  });

  test.describe('Session Management', () => {
    /**
     * P0-API-010: Get current session
     *
     * AC1: Given usuario autenticado
     *       When consulta su sesión actual
     *       Then recibe respuesta 200 OK
     *       And response contiene user data
     *
     * Contract Test:
     * - Response status: 200
     * - Response body: { user: { id, email, name, capabilities[] } }
     */
    test('[P0-API-010] should get current session', async ({ request }) => {
      const loginResponse = await request.post(`${baseURL}/api/auth/callback/credentials`, {
        data: {
          email: 'admin@hiansa.com',
          password: 'admin123',
        },
      });

      const cookies = loginResponse.headers()['set-cookie'];
      const cookieHeader = cookies?.split(';')[0] || '';

      const response = await request.get(`${baseURL}/api/auth/session`, {
        headers: {
          'Cookie': cookieHeader,
        },
      });

      expect(response.status()).toBe(200);
      const body = await response.json();
      expect(body).toHaveProperty('user');
      expect(body.user).toHaveProperty('id');
      expect(body.user).toHaveProperty('email');
      expect(body.user).toHaveProperty('capabilities');
    });

    /**
     * P0-API-011: Session expires after timeout
     *
     * AC2: Given sesión inactiva por 8 horas
     *       When intenta hacer request
     *       Then recibe respuesta 401 Unauthorized
     *
     * Contract Test:
     * - Response status: 401
     * - Response body: { error: string }
     */
    test('[P0-API-011] should expire session after timeout', async ({ request }) => {
      // This test would require manipulating session expiration
      // Skip for now as it requires time manipulation
      test.skip(true, 'Requires session expiration manipulation');
    });
  });

  test.describe('Contract Tests - Auth API', () => {
    /**
     * Contract Test: Verify Auth API response schemas
     *
     * Tests that the Auth API responses match the expected schemas
     * for consumer contract verification with Pact.js
     */
    test('[CONTRACT] should return correct response schema for login', async ({ request }) => {
      const loginData = {
        email: 'admin@hiansa.com',
        password: 'admin123',
      };

      const response = await request.post(`${baseURL}/api/auth/callback/credentials`, {
        data: loginData,
        headers: {
          'Content-Type': 'application/json',
        },
      });

      expect([200, 302]).toContain(response.status());

      if (response.status() === 200) {
        const body = await response.json();

        // Verify response schema
        expect(body).toMatchObject({
          user: expect.objectContaining({
            id: expect.any(String),
            email: expect.any(String),
            name: expect.any(String),
            capabilities: expect.any(Array),
          }),
        });
      }
    });

    test('[CONTRACT] should return correct error schema for failed login', async ({ request }) => {
      const loginData = {
        email: 'admin@hiansa.com',
        password: 'wrongpassword',
      };

      const response = await request.post(`${baseURL}/api/auth/callback/credentials`, {
        data: loginData,
        headers: {
          'Content-Type': 'application/json',
        },
      });

      if (response.status() === 401) {
        const body = await response.json();

        // Verify error response schema
        expect(body).toMatchObject({
          error: expect.any(String),
        });
      }
    });
  });
});

/**
 * API Tests: User Management Endpoints
 * Epic 1: User Authentication and Management
 *
 * P0-API-010 to P1-API-015
 *
 * Tests cover:
 * - GET /api/users (P0)
 * - POST /api/users (P0)
 * - GET /api/users/:id (P1)
 * - PUT /api/users/:id (P1)
 * - DELETE /api/users/:id (P1)
 *
 * Testing Approach:
 * - Uses Playwright's APIRequestContext for direct API calls
 * - Tests CRUD operations for user management
 * - Validates PBAC capability checks
 * - Tests soft delete functionality
 * - Includes contract tests for request/response schemas
 *
 * Contract Testing:
 * - Uses Pact.js patterns for provider state verification
 * - Validates response schemas match consumer expectations
 * - Tests pagination, filtering, and sorting
 */

import { test, expect } from '@playwright/test';
import { faker } from '@faker-js/faker/locale/es';

/**
 * User API Tests
 *
 * Note: These tests require admin authentication (can_manage_users capability).
 * Tests verify the complete user management lifecycle including:
 * - Listing users with filtering
 * - Creating users with capabilities
 * - Updating user profiles
 * - Soft deleting users
 */

test.describe('User API Endpoints', () => {
  let baseURL: string;
  let adminCookie: string;
  let adminUserId: string;

  test.beforeAll(async ({ request }) => {
    baseURL = process.env.BASE_URL || 'http://localhost:3000';

    // Login as admin to get session cookie
    const loginResponse = await request.post(`${baseURL}/api/auth/callback/credentials`, {
      data: {
        email: 'admin@hiansa.com',
        password: 'admin123',
      },
    });

    const cookies = loginResponse.headers()['set-cookie'];
    adminCookie = cookies?.split(';')[0] || '';

    // Get admin user ID
    const sessionResponse = await request.get(`${baseURL}/api/auth/session`, {
      headers: {
        'Cookie': adminCookie,
      },
    });

    if (sessionResponse.ok()) {
      const sessionData = await sessionResponse.json();
      adminUserId = sessionData.user?.id || '';
    }
  });

  test.describe('GET /api/v1/users', () => {
    /**
     * P0-API-010: List all users (admin only)
     *
     * AC1: Given admin autenticado
     *       When lista todos los usuarios
     *       Then recibe respuesta 200 OK
     *       And response contiene arreglo de usuarios
     *       And cada usuario tiene id, email, name, capabilities
     *
     * Contract Test:
     * - Response status: 200
     * - Response body: { users: [{ id, email, name, capabilities[], ... }] }
     */
    test('[P0-API-010] should list all users for admin', async ({ request }) => {
      const response = await request.get(`${baseURL}/api/v1/users`, {
        headers: {
          'Cookie': adminCookie,
        },
      });

      expect(response.status()).toBe(200);

      const body = await response.json();
      expect(body).toHaveProperty('users');
      expect(Array.isArray(body.users)).toBeTruthy();

      // Verify user structure
      if (body.users.length > 0) {
        const firstUser = body.users[0];
        expect(firstUser).toHaveProperty('id');
        expect(firstUser).toHaveProperty('email');
        expect(firstUser).toHaveProperty('name');
        expect(firstUser).toHaveProperty('capabilities');
        expect(Array.isArray(firstUser.capabilities)).toBeTruthy();
      }
    });

    /**
     * P0-API-011: List users fails without authentication
     *
     * AC2: Given sin autenticación
     *       When intenta listar usuarios
     *       Then recibe respuesta 401 Unauthorized
     *
     * Contract Test:
     * - Response status: 401
     * - Response body: { error: string }
     */
    test('[P0-API-011] should fail to list users without authentication', async ({ request }) => {
      const response = await request.get(`${baseURL}/api/v1/users`);

      expect(response.status()).toBe(401);

      const body = await response.json();
      expect(body).toHaveProperty('error');
    });

    /**
     * P0-API-012: List users fails without can_manage_users capability
     *
     * AC3: Given usuario autenticado sin can_manage_users
     *       When intenta listar usuarios
     *       Then recibe respuesta 403 Forbidden
     *
     * Contract Test:
     * - Response status: 403
     * - Response body: { error: string }
     */
    test('[P0-API-012] should fail to list users without can_manage_users capability', async ({ request }) => {
      // Login as tecnico user (doesn't have can_manage_users)
      const loginResponse = await request.post(`${baseURL}/api/auth/callback/credentials`, {
        data: {
          email: 'tecnico@hiansa.com',
          password: 'tecnico123',
        },
      });

      const cookies = loginResponse.headers()['set-cookie'];
      const tecnicoCookie = cookies?.split(';')[0] || '';

      const response = await request.get(`${baseURL}/api/v1/users`, {
        headers: {
          'Cookie': tecnicoCookie,
        },
      });

      expect(response.status()).toBe(403);

      const body = await response.json();
      expect(body).toHaveProperty('error');
      expect(body.error).toContain('permiso');
    });

    /**
     * P1-API-001: List users excludes soft-deleted users
     *
     * AC4: Given usuarios eliminados (deleted=true)
     *       When lista todos los usuarios
     *       Then response NO incluye usuarios con deleted=true
     *
     * Contract Test:
     * - Response status: 200
     * - Response body: { users: [...] }
     * - Ningún usuario tiene deleted: true
     */
    test('[P1-API-001] should exclude soft-deleted users from list', async ({ request }) => {
      const response = await request.get(`${baseURL}/api/v1/users`, {
        headers: {
          'Cookie': adminCookie,
        },
      });

      expect(response.status()).toBe(200);

      const body = await response.json();
      expect(body).toHaveProperty('users');

      // Verify no deleted users in response
      body.users.forEach((user: any) => {
        expect(user.deleted).toBeFalsy();
      });
    });

    /**
     * P1-API-002: List users sorted by creation date
     *
     * AC5: Given múltiples usuarios
     *       When lista todos los usuarios
     *       Then usuarios están ordenados por createdAt descendente
     *
     * Contract Test:
     * - Response status: 200
     * - Response body: { users: [...] }
     * - Usuarios ordenados por createdAt DESC
     */
    test('[P1-API-002] should return users sorted by creation date', async ({ request }) => {
      const response = await request.get(`${baseURL}/api/v1/users`, {
        headers: {
          'Cookie': adminCookie,
        },
      });

      expect(response.status()).toBe(200);

      const body = await response.json();
      expect(body.users.length).toBeGreaterThan(0);

      // Verify sorting (newest first)
      for (let i = 0; i < body.users.length - 1; i++) {
        const currentDate = new Date(body.users[i].createdAt);
        const nextDate = new Date(body.users[i + 1].createdAt);
        expect(currentDate >= nextDate).toBeTruthy();
      }
    });
  });

